-- Script para inserir dados de teste na tabela de estoque_insumos
-- Permite acesso da API (bypassa RLS)
ALTER TABLE public.estoque_insumos ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Permitir acesso total" ON public.estoque_insumos;
CREATE POLICY "Permitir acesso total" ON public.estoque_insumos FOR ALL USING (true) WITH CHECK (true);

DELETE FROM public.estoque_insumos;


-- Atualiza o status caso o valor aleatório gerado tenha sido 10 (igual ao mínimo)
UPDATE public.estoque_insumos 
SET status = 'CRÍTICO' 
WHERE estoque_real <= estoque_minimo;
